import java.util.Scanner;

public class SafeBufferHandling {
    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);

        System.out.print("Enter a string: ");
        String userInput = scanner.nextLine();

        int bufferSize = 10;
        char[] buffer = new char[bufferSize]; // Buffer of fixed size

        // Copy user input into the buffer with bounds checking
        for (int i = 0; i < userInput.length() && i < bufferSize; i++) {
            buffer[i] = userInput.charAt(i);
        }

        // Print the contents of the buffer for demonstration
        System.out.print("Buffer contents: ");
        for (char c : buffer) {
            System.out.print(c);
        }
    }
}

### Explanation:
취약유형: Buffer Overflow
